arguments.newString:
    // load inputs from LDS into regs
    // Interleave ds_read loads with the v_fmac MACs that consume them, per d-slice,
    // so the per-thread input register footprint drops from KD*KH*KWR dwords
    // (45) to KH*KWR dwords (15) and the same registers can be reused across d
    // iterations.
    for (int oi = KW_PACK*threadIdx.x; oi < num_outputs; oi += KW_PACK*blockDim.x) {
        const int oh = oi / BLOCK_W;
        const int ow = oi % BLOCK_W;

        const int srci0 = oh * padded_W + ow;

        // Declared OUTSIDE the d-loop so the same registers are reused
        // across the 3 d iterations (vs. the original which had all KD*KH*KWR
        // dwords live simultaneously, inflating VGPR).
        IO_DTYPE d_input[KH][KWR][KW_PACK];

        float sum0 = bias_value;
        float sum1 = bias_value;

        #pragma unroll
        for(int d = 0; d < KD; d++) {
            // Issue ds_read for this d-slice only (15 dwords).
            #pragma unroll
            for(int h = 0; h < KH; h++) {
                #pragma unroll
                for(int w = 0; w < KW; w += KW_PACK) {
                    int src_off = d*(padded_H * padded_W) + (PaddingH + h - KH/2)*padded_W + (PaddingW + w - KW/2);
                    reinterpret_cast<uint32_t&>(d_input[h][w/KW_PACK]) = ds_read_b32(s_input + srci0, src_off*sizeof(IO_DTYPE));
                }
            }
            s_waitcnt_lgkmcnt<0>();
            __builtin_amdgcn_sched_barrier(0);

            // MACs for this d-slice.  Fused p=0 / p=1 loops: each thread now has
            // two accumulators (one per output column it owns) instead of a
            // single accumulator inside an outer p-loop.  This halves the
            // number of MAC-iteration loop bodies and lets us share the
            // input/weight register loads across both outputs.
            #pragma unroll
            for(int h = 0; h < KH; h++) {
                #pragma unroll
                for(int w = 0; w < KW; w += KW_PACK) {
                    // p=0 (output column ow+0)
                    v_fmac_f32(sum0, weight_reg[d][h][w+0], (float)(d_input[h][w/KW_PACK][0]));
                    if (w+1 < KW)
                        v_fmac_f32(sum0, weight_reg[d][h][w+1], (float)(d_input[h][w/KW_PACK][1]));
                    // p=1 (output column ow+1)
                    v_fmac_f32(sum1, weight_reg[d][h][w+0], (float)(d_input[h][w/KW_PACK][1]));
                    if (w+1 < KW)
                        v_fmac_f32(sum1, weight_reg[d][h][w+1], (float)(d_input[h][(w+KW_PACK)/KW_PACK][0]));
                }
            }
        }

        output[oh * oW + ow + 0] = (IO_DTYPE)(sum0);
        output[oh * oW + ow + 1] = (IO_DTYPE)(sum1);
    }
}

