                float w1 = ds_read_b32_float(s_weight + wbase, 4);
                float w2 = ds_read_b32_float(s_weight + wbase, 8);
                float w3 = ds_read_b32_float(s_weight + wbase, 12);
                float w4 = ds_read_b32_float(s_weight + wbase, 16);

