                v_fmac_f32(sum1, w0, (float)(d_input[h][0][1]));
                v_fmac_f32(sum1, w1, (float)(d_input[h][1][0]));
                v_fmac_f32(sum1, w2, (float)(d_input[h][1][1]));
                v_fmac_f32(sum1, w3, (float)(d_input[h][2][0]));
                v_fmac_f32(sum1, w4, (float)(d_input[h][2][1]));
            }
        }

