#include <hip/hip_runtime.h>
#include <hip/hip_fp16.h>
#include <hip/hip_bf16.h>

#define dilationD 1
#define dilationH 1
#define dilationW 1
#define strideT 1
#define strideH 1
#define strideW 1

template<typename T>
constexpr T div_up(T a, T b) { return (a + b - 1) / b; }

