    // them, per d-slice.  Per-thread input register footprint drops from
    // KD*KH*KWR dwords (45) to KH*KWR dwords (15) and the same registers
    // are reused across d iterations.  Weights are read from s_weight via
    // ds_read_b32 broadcast loads in 5-float chunks (one row at a time),
    // so we never hold more than ~5 weight vregs at once.
    for (int oi = KW_PACK*threadIdx.x; oi < num_outputs; oi += KW_PACK*blockDim.x) {
        const int oh = oi / BLOCK_W;
        const int ow = oi % BLOCK_W;
        const int srci0 = oh * padded_W + ow;

        IO_DTYPE d_input[KH][KWR][KW_PACK];

        float sum0 = bias_value;
        float sum1 = bias_value;

