            const int off_h1 = d * padded_H * padded_W + (h + PaddingH) * padded_W + PaddingW;
            #pragma unroll
            for (int w = lane_id; w < BLOCK_W/2; w += warp_size) {
                set_m0(s_input + off_h1 + 2*__builtin_amdgcn_readfirstlane(w));
                global_load_lds_dword(off_h0 * sizeof(IO_DTYPE) + w*sizeof_dword, input);
            }
        }
    }

    int ki = 0;
    #pragma unroll
    for(int d = 0; d < KD; d ++) {
        #pragma unroll
        for(int h = 0; h < KH; h++) {
            #pragma unroll
            for(int w = 0; w < KW; w++) {
                weight_reg[d][h][w] = kernel[ki++];
            }
        }
    }
    float bias_value = 0.0f;
    if (bias != nullptr)
        bias_value = bias[out_channel];

    s_waitcnt_vmcnt<0>();
    __syncthreads();

    constexpr int num_outputs = BLOCK_H * BLOCK_W;
    constexpr int KW_PACK = 2;
    constexpr int KWR = div_up(KW, KW_PACK);
    static_assert(BLOCK_W % 2 == 0);

    // Hot loop.  Two changes from the original:
    //
    //  (1) "load everything then compute everything" is replaced by a
    //      per-d-slice schedule: for each of the 3 d-slices we issue the
    //      15 ds_reads that bring the slice's BF16 inputs into registers,
    //      s_waitcnt_lgkmcnt<0>, and then run the 25 v_fmac MACs that
    //      consume them.  Because the 15 dword d_input[] array is reused
    //      across the 3 d iterations, the per-thread input register
    //      footprint drops from KD*KH*KWR=45 dwords to KH*KWR=15 dwords.
    //
    //  (2) The p=0 / p=1 outer loops are fused: instead of doing a full
    //      pass over the kernel for output column ow, then a full pass
    //      for column ow+1, both accumulators advance together inside a
    //      single (d, h, w) loop.  This shares the input and weight
    //      register reads across the two output columns.
    for (int oi = KW_PACK*threadIdx.x; oi < num_outputs; oi += KW_PACK*blockDim.x) {
        const int oh = oi / BLOCK_W;
        const int ow = oi % BLOCK_W;
        const int srci0 = oh * padded_W + ow;

        IO_DTYPE d_input[KH][KWR][KW_PACK];

        float sum0 = bias_value;
        float sum1 = bias_value;

        #pragma unroll
        for(int d = 0; d < KD; d++) {
            // Issue ds_read for this d-slice only (15 dwords).
            #pragma unroll
            for(int h = 0; h < KH; h++) {
                #pragma unroll
                for(int w = 0; w < KW; w += KW_PACK) {
                    int src_off = d*(padded_H * padded_W) + (PaddingH + h - KH/2)*padded_W + (PaddingW + w - KW/2);
                    reinterpret_cast<uint32_t&>(d_input[h][w/KW_PACK]) = ds_read_b32(s_input + srci0, src_off*sizeof(IO_DTYPE));
                }
            }
            s_waitcnt_lgkmcnt<0>();
            __builtin_amdgcn_sched_barrier(0);

            // MACs for this d-slice.  Combined p=0 / p=1 fused into single loop.
            #pragma unroll
            for(int h = 0; h < KH; h++) {
                #pragma unroll
                for(int w = 0; w < KW; w += KW_PACK) {
                    v_fmac_f32(sum0, weight_reg[d][h][w+0], (float)(d_input[h][w/KW_PACK][0]));
                    if (w+1 < KW)
                        v_fmac_f32(sum0, weight_reg[d][h][w+1], (float)(d_input[h][w/KW_PACK][1]));
                    v_fmac_f32(sum1, weight_reg[d][h][w+0], (float)(d_input[h][w/KW_PACK][1]));
                    if (w+1 < KW)
                        v_fmac_f32(sum1, weight_reg[d][h][w+1], (float)(d_input[h][(w+KW_PACK)/KW_PACK][0]));
                }
            }
        }

        output[oh * oW + ow + 0] = (IO_DTYPE)(sum0);
        output[oh * oW + ow + 1] = (IO_DTYPE)(sum1);
    }
}
